    [500] = {id=500,name="Mog House Exit: San d'Oria",description="Speak to Kuu Mohzolhi in Northern San d'Oria (F-8) and complete the quest \"Growing Flowers\" to expand the number of destinations to which you may travel from your Mog House.",objcount=1,sparks=100,exp=300,cp=0,accolades=0,plaudits=0},
