    [505] = {id=505,name="Obtain a Support Job",description="Speak to Isacio in Selbina (G-10) and complete the quest \"Elder Memories\" or speak to Vera in Mhaura (G-10) and complete the quest \"The Old Lady\" to obtain a support job. Requirement: Be level 18 or higher.",objcount=1,sparks=100,exp=500,cp=0,accolades=0,plaudits=0},
    [506] = {id=506,name="Obtain an Alter Ego: San d'Oria",description="Speak to Gondebaud in Southern San d'Oria (L-6), complete the quest \"Trust: San d'Oria,\" and obtain an alter ego of Excenmille. Requirement: Be level 5 or higher.",objcount=1,sparks=100,exp=500,cp=0,accolades=0,plaudits=0},
    [507] = {id=507,name="Obtain an Alter Ego: Bastok",description="Speak to Clarion Star in Port Bastok (K-7), complete the quest \"Trust: Bastok,\" and obtain an alter ego of Naji. Requirement: Be level 5 or higher.",objcount=1,sparks=100,exp=500,cp=0,accolades=0,plaudits=0},
    [508] = {id=508,name="Obtain an Alter Ego: Windurst",description="Speak to Wetata in Windurst Woods (G-10), complete the quest \"Trust: Windurst,\" and obtain an alter ego of Kupipi. Requirement: Be level 5 or higher.",objcount=1,sparks=100,exp=500,cp=0,accolades=0,plaudits=0},
    [509] = {id=509,name="Obtain a Chocobo License",description="Speak to Brutus in Upper Jeuno (G-7), complete the quest \"Chocobo's Wounds,\" and obtain a chocobo license. Requirement: Be level 20 or higher.",objcount=1,sparks=100,exp=600,cp=0,accolades=0,plaudits=0},
